const reestr_data = $("GetReestr").all();
const result = new Map();

for (let item of reestr_data) {
  let date_key =
    item.json['Дата окончания (фикс)'] ||
    item.json['Дата выдачи'] ||
    item.json['Дата создания'];

  if (!result.has(date_key)) {
    result.set(date_key, {
      date: date_key,      // 👈 явное поле вместо ключа
      requests: []
    });
  }

  result.get(date_key).requests.push(item.json);
}

return Array.from(result.values()).map(group => ({
  json: group
}));

const folder_data = $("Copy file").all();
const requests_data = $("MakeGroupsByDate").all();
const grps = $('GroupDict').first().json.group_dict;

const results = [];

for (let i = 0; i < requests_data.length; i++) {
  const file_id = folder_data[i].json.id;
  const group = requests_data[i].json; // 👈 теперь просто объект
  const requests = group.requests;

  for (let request of requests) {
    const regNumbers = request['Рег-номер (Выписка)'].split(',');

    for (let rgnm of regNumbers) {
      let [grp, rn] = rgnm.split(':');

      results.push({
        fio: request['Фамилия Имя Отчество'],
        snils: request['СНИЛС'],
        jobPost: request['Должность'],
        INN: request['ИНН организации'],
        company: request['Компания'],
        progNum: grps[grp],
        dt: request['Дата окончания (фикс)'] ||
            request['Дата выдачи'] ||
            request['Дата создания'],
        protNum: rn,
        file: file_id
      });
    }
  }
}

return results;

const groups = $('GetGroups').all();
const dictionary = {};

for (let obj of groups){
  dictionary[obj.json['Группа']] = obj.json['Нумерация для Минтруда'];
}

return {group_dict: dictionary}

